#[async_trait]
impl<R: FileShareProjectionRepository> FileShareEventHandler for FileShareProjector<R> {

    async fn on_created(&self, event: FileShareCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = FileShareProjection::new(
            event.id,
            event.file_id,
            event.owner_id,
            event.token,
            event.share_type,
            event.permission,
            event.shared_with,
            event.password_hash,
            event.max_downloads,
            event.download_count,
            event.expires_at,
            event.share_status,
            event.is_active,
            event.revoked_at,
            event.revoked_by,
            event.message,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: FileShareUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.file_id = event.file_id;
            projection.owner_id = event.owner_id;
            projection.token = event.token;
            projection.share_type = event.share_type;
            projection.permission = event.permission;
            projection.shared_with = event.shared_with;
            projection.password_hash = event.password_hash;
            projection.max_downloads = event.max_downloads;
            projection.download_count = event.download_count;
            projection.expires_at = event.expires_at;
            projection.share_status = event.share_status;
            projection.is_active = event.is_active;
            projection.revoked_at = event.revoked_at;
            projection.revoked_by = event.revoked_by;
            projection.message = event.message;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: FileShareDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

